	// selected debugger runtime. This stores metadata only in control-plane DB.
	LoadDebugDataset(context.Context, *LoadDebugDatasetRequest) (*LoadDebugDatasetResponse, error)
	// GetRuntimeDebugDataset returns the latest active/lost/failed dataset
	// metadata for one runtime. Full K-line rows are never returned.
	GetRuntimeDebugDataset(context.Context, *GetRuntimeDebugDatasetRequest) (*GetRuntimeDebugDatasetResponse, error)
	// PublishRuntimeNotification is the unified runtime/strategy notification
	// ingress. Hosted and self-hosted runtimes both enter the same control-plane
	// path before the event is published to Kafka notification.events.
	PublishRuntimeNotification(context.Context, *PublishRuntimeNotificationRequest) (*PublishRuntimeNotificationResponse, error)
	RunStrategy(context.Context, *strategyv1.RunStrategyRequest) (*strategyv1.RunStrategyResponse, error)
	PreviewRunStrategy(context.Context, *strategyv1.PreviewRunStrategyRequest) (*strategyv1.PreviewRunStrategyResponse, error)
	StopStrategy(context.Context, *strategyv1.StopStrategyRequest) (*strategyv1.StopStrategyResponse, error)
